-- ============================================================
-- DATA ANALYTICS FOR PREDICTING STUDENTS ACADEMIC PERFORMANCE
-- AFE BABALOLA UNIVERSITY ADO-EKITI (ABUAD)
-- 1000 STUDENTS | 10 DEPARTMENTS | 5 COLLEGES | 2024/2025
-- ============================================================
-- Colleges:
--   College of Engineering (Electrical/Electronics Eng, Petroleum Eng)
--   College of Medicine and Health Sciences (Medicine & Surgery, Pharmacy)
--   College of Law (Civil Law, Public Law)
--   College of Sciences (Computer Science, Microbiology)
--   College of Social and Management Sciences (Accounting, Economics)
-- ============================================================

DROP DATABASE IF EXISTS abuad_student_analytics;
CREATE DATABASE abuad_student_analytics
  CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE abuad_student_analytics;

-- ── TABLES ────────────────────────────────────────────────────────────────

CREATE TABLE Students (
    student_id       VARCHAR(20)  PRIMARY KEY,
    full_name        VARCHAR(100) NOT NULL,
    gender           ENUM('Male','Female','Other') NOT NULL,
    department       VARCHAR(100) NOT NULL,
    college          VARCHAR(100) NOT NULL,
    level            SMALLINT     NOT NULL,
    entry_year       YEAR         NOT NULL,
    email            VARCHAR(150) UNIQUE,
    created_at       TIMESTAMP    DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE Courses (
    course_id        VARCHAR(20)  PRIMARY KEY,
    course_name      VARCHAR(150) NOT NULL,
    credit_units     TINYINT      NOT NULL DEFAULT 3,
    department       VARCHAR(100) NOT NULL,
    college          VARCHAR(100) NOT NULL,
    level            SMALLINT     NOT NULL,
    semester         ENUM('First','Second') NOT NULL
);

CREATE TABLE Grades (
    grade_id         INT          AUTO_INCREMENT PRIMARY KEY,
    student_id       VARCHAR(20)  NOT NULL,
    course_id        VARCHAR(20)  NOT NULL,
    academic_year    VARCHAR(10)  NOT NULL,
    semester         ENUM('First','Second') NOT NULL,
    ca_score         DECIMAL(5,2) NOT NULL DEFAULT 0,
    exam_score       DECIMAL(5,2) NOT NULL DEFAULT 0,
    total_score      DECIMAL(5,2) GENERATED ALWAYS AS (ca_score + exam_score) STORED,
    grade_letter     VARCHAR(2)   DEFAULT NULL,
    grade_point      DECIMAL(3,1) DEFAULT NULL,
    FOREIGN KEY (student_id) REFERENCES Students(student_id) ON DELETE CASCADE,
    FOREIGN KEY (course_id)  REFERENCES Courses(course_id)   ON DELETE CASCADE,
    UNIQUE KEY uq_grade (student_id, course_id, academic_year, semester)
);

CREATE TABLE Attendance (
    attendance_id    INT          AUTO_INCREMENT PRIMARY KEY,
    student_id       VARCHAR(20)  NOT NULL,
    course_id        VARCHAR(20)  NOT NULL,
    academic_year    VARCHAR(10)  NOT NULL,
    semester         ENUM('First','Second') NOT NULL,
    total_classes    INT          NOT NULL DEFAULT 0,
    classes_attended INT          NOT NULL DEFAULT 0,
    attendance_pct   DECIMAL(5,2) GENERATED ALWAYS AS (
                         CASE WHEN total_classes = 0 THEN 0
                              ELSE ROUND((classes_attended / total_classes) * 100, 2)
                         END) STORED,
    FOREIGN KEY (student_id) REFERENCES Students(student_id) ON DELETE CASCADE,
    FOREIGN KEY (course_id)  REFERENCES Courses(course_id)   ON DELETE CASCADE,
    UNIQUE KEY uq_attendance (student_id, course_id, academic_year, semester)
);

CREATE TABLE Engagement (
    engagement_id         INT          AUTO_INCREMENT PRIMARY KEY,
    student_id            VARCHAR(20)  NOT NULL,
    academic_year         VARCHAR(10)  NOT NULL,
    semester              ENUM('First','Second') NOT NULL,
    study_hours_per_week  DECIMAL(4,1) NOT NULL DEFAULT 0,
    assignments_submitted INT          NOT NULL DEFAULT 0,
    assignments_total     INT          NOT NULL DEFAULT 10,
    library_visits        INT          NOT NULL DEFAULT 0,
    FOREIGN KEY (student_id) REFERENCES Students(student_id) ON DELETE CASCADE,
    UNIQUE KEY uq_engagement (student_id, academic_year, semester)
);

CREATE TABLE Risk_Predictions (
    prediction_id    INT          AUTO_INCREMENT PRIMARY KEY,
    student_id       VARCHAR(20)  NOT NULL,
    academic_year    VARCHAR(10)  NOT NULL,
    semester         ENUM('First','Second') NOT NULL,
    avg_ca_score     DECIMAL(5,2),
    avg_exam_score   DECIMAL(5,2),
    avg_attendance   DECIMAL(5,2),
    avg_study_hours  DECIMAL(4,1),
    risk_score       DECIMAL(5,2),
    risk_category    ENUM('On Track','Needs Monitoring','At Risk') NOT NULL,
    predicted_on     TIMESTAMP    DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (student_id) REFERENCES Students(student_id) ON DELETE CASCADE,
    UNIQUE KEY uq_prediction (student_id, academic_year, semester)
);

-- ── STUDENTS (1,000) ─────────────────────────────────────────────────────

-- ── COURSES (30) ─────────────────────────────────────────────────────────

-- ── GRADES (3,000) ───────────────────────────────────────────────────────

-- ── ATTENDANCE (3,000) ───────────────────────────────────────────────────

-- ── ENGAGEMENT (1,000) ───────────────────────────────────────────────────

-- ── VIEWS ─────────────────────────────────────────────────────────────────

CREATE OR REPLACE VIEW vw_student_semester_summary AS
SELECT
    s.student_id, s.full_name, s.gender, s.department, s.college, s.level,
    g.academic_year, g.semester,
    ROUND(AVG(g.ca_score),   2) AS avg_ca_score,
    ROUND(AVG(g.exam_score), 2) AS avg_exam_score,
    ROUND(AVG(g.total_score),2) AS avg_total_score,
    ROUND(AVG(a.attendance_pct), 2) AS avg_attendance_pct,
    COALESCE(e.study_hours_per_week,  0) AS study_hours_per_week,
    COALESCE(e.assignments_submitted, 0) AS assignments_submitted,
    COALESCE(e.assignments_total,    10) AS assignments_total,
    ROUND(COALESCE(e.assignments_submitted,0) /
          NULLIF(COALESCE(e.assignments_total,10),0) * 100, 2) AS assignment_completion_pct
FROM Students s
JOIN Grades     g  ON s.student_id  = g.student_id
JOIN Attendance a  ON s.student_id  = a.student_id
                  AND g.course_id    = a.course_id
                  AND g.academic_year= a.academic_year
                  AND g.semester     = a.semester
LEFT JOIN Engagement e ON s.student_id   = e.student_id
                       AND g.academic_year = e.academic_year
                       AND g.semester      = e.semester
GROUP BY s.student_id, s.full_name, s.gender, s.department, s.college, s.level,
         g.academic_year, g.semester,
         e.study_hours_per_week, e.assignments_submitted, e.assignments_total;


CREATE OR REPLACE VIEW vw_risk_scores AS
SELECT
    student_id, full_name, gender, department, college, level,
    academic_year, semester,
    avg_ca_score, avg_exam_score, avg_total_score,
    avg_attendance_pct, study_hours_per_week, assignment_completion_pct,
    ROUND((avg_ca_score   / 40) * 100, 2) AS X1_ca_normalised,
    ROUND((avg_exam_score / 60) * 100, 2) AS X2_exam_normalised,
    avg_attendance_pct                    AS X3_attendance,
    ROUND(LEAST(study_hours_per_week / 25 * 100, 100), 2) AS X4_engagement,
    ROUND(
        0.4 * ((avg_ca_score   / 40) * 100) +
        0.3 * ((avg_exam_score / 60) * 100) +
        0.2 *   avg_attendance_pct           +
        0.1 * LEAST(study_hours_per_week / 25 * 100, 100),
    2) AS risk_score,
    CASE
        WHEN (0.4*((avg_ca_score/40)*100)+0.3*((avg_exam_score/60)*100)+
              0.2*avg_attendance_pct+0.1*LEAST(study_hours_per_week/25*100,100)) >= 70
             THEN 'On Track'
        WHEN (0.4*((avg_ca_score/40)*100)+0.3*((avg_exam_score/60)*100)+
              0.2*avg_attendance_pct+0.1*LEAST(study_hours_per_week/25*100,100)) >= 50
             THEN 'Needs Monitoring'
        ELSE 'At Risk'
    END AS risk_category
FROM vw_student_semester_summary;


CREATE OR REPLACE VIEW vw_course_performance AS
SELECT
    c.course_id, c.course_name, c.credit_units, c.department, c.college,
    g.academic_year, g.semester,
    COUNT(DISTINCT g.student_id)                                      AS enrolled_students,
    ROUND(AVG(g.total_score), 2)                                      AS avg_total_score,
    ROUND(MIN(g.total_score), 2)                                      AS min_score,
    ROUND(MAX(g.total_score), 2)                                      AS max_score,
    SUM(CASE WHEN g.total_score <  40 THEN 1 ELSE 0 END)             AS fail_count,
    SUM(CASE WHEN g.total_score >= 70 THEN 1 ELSE 0 END)             AS distinction_count,
    ROUND(SUM(CASE WHEN g.total_score < 40 THEN 1 ELSE 0 END)
          / COUNT(*) * 100, 1)                                        AS failure_rate_pct
FROM Courses c
JOIN Grades  g ON c.course_id = g.course_id
GROUP BY c.course_id, c.course_name, c.credit_units, c.department, c.college,
         g.academic_year, g.semester;


CREATE OR REPLACE VIEW vw_at_risk_students AS
SELECT student_id, full_name, gender, department, college, level,
       academic_year, semester, avg_ca_score, avg_exam_score,
       avg_total_score, avg_attendance_pct, study_hours_per_week,
       assignment_completion_pct, risk_score, risk_category
FROM vw_risk_scores
WHERE risk_category IN ('At Risk','Needs Monitoring')
ORDER BY risk_score ASC;


CREATE OR REPLACE VIEW vw_department_summary AS
SELECT
    department, college,
    COUNT(DISTINCT student_id)                                           AS total_students,
    ROUND(AVG(avg_total_score), 2)                                       AS dept_avg_score,
    ROUND(AVG(avg_attendance_pct), 2)                                    AS dept_avg_attendance,
    ROUND(AVG(study_hours_per_week), 1)                                  AS dept_avg_study_hrs,
    SUM(CASE WHEN risk_category = 'At Risk'          THEN 1 ELSE 0 END) AS at_risk_count,
    SUM(CASE WHEN risk_category = 'Needs Monitoring' THEN 1 ELSE 0 END) AS monitoring_count,
    SUM(CASE WHEN risk_category = 'On Track'         THEN 1 ELSE 0 END) AS on_track_count
FROM vw_risk_scores
GROUP BY department, college;


CREATE OR REPLACE VIEW vw_college_summary AS
SELECT
    college,
    COUNT(DISTINCT student_id)                                           AS total_students,
    COUNT(DISTINCT department)                                           AS departments,
    ROUND(AVG(avg_total_score), 2)                                       AS college_avg_score,
    ROUND(AVG(avg_attendance_pct), 2)                                    AS college_avg_attendance,
    ROUND(AVG(study_hours_per_week), 1)                                  AS college_avg_study_hrs,
    SUM(CASE WHEN risk_category = 'At Risk'          THEN 1 ELSE 0 END) AS at_risk_count,
    SUM(CASE WHEN risk_category = 'Needs Monitoring' THEN 1 ELSE 0 END) AS monitoring_count,
    SUM(CASE WHEN risk_category = 'On Track'         THEN 1 ELSE 0 END) AS on_track_count,
    ROUND(SUM(CASE WHEN risk_category = 'At Risk' THEN 1 ELSE 0 END)
          / COUNT(*) * 100, 1)                                           AS at_risk_pct
FROM vw_risk_scores
GROUP BY college;


-- ── STORED PROCEDURE ──────────────────────────────────────────────────────
DELIMITER $$
CREATE PROCEDURE sp_populate_risk_predictions(
    IN p_year     VARCHAR(10),
    IN p_semester ENUM('First','Second')
)
BEGIN
         avg_attendance, avg_study_hours, risk_score, risk_category)
    SELECT student_id, academic_year, semester, avg_ca_score, avg_exam_score,
           avg_attendance_pct, study_hours_per_week, risk_score, risk_category
    FROM vw_risk_scores
    WHERE academic_year = p_year AND semester = p_semester
    ON DUPLICATE KEY UPDATE
        avg_ca_score   = VALUES(avg_ca_score),
        avg_exam_score = VALUES(avg_exam_score),
        avg_attendance = VALUES(avg_attendance),
        avg_study_hours= VALUES(avg_study_hours),
        risk_score     = VALUES(risk_score),
        risk_category  = VALUES(risk_category),
        predicted_on   = NOW();
END$$
DELIMITER ;


-- ── VERIFICATION QUERIES ──────────────────────────────────────────────────

-- 1. Record counts
SELECT 'Students'   AS tbl, COUNT(*) AS records FROM Students
UNION ALL SELECT 'Courses',    COUNT(*) FROM Courses
UNION ALL SELECT 'Grades',     COUNT(*) FROM Grades
UNION ALL SELECT 'Attendance', COUNT(*) FROM Attendance
UNION ALL SELECT 'Engagement', COUNT(*) FROM Engagement;

-- 2. Risk distribution
SELECT risk_category,
       COUNT(*) AS count,
       ROUND(COUNT(*)*100.0/1000,1) AS pct,
       ROUND(AVG(avg_total_score),2) AS avg_score,
       ROUND(AVG(avg_attendance_pct),2) AS avg_attendance
FROM vw_risk_scores
WHERE academic_year='2024/2025' AND semester='First'
GROUP BY risk_category
ORDER BY FIELD(risk_category,'At Risk','Needs Monitoring','On Track');

-- 3. NULL check (all should return 0)
SELECT
    SUM(CASE WHEN avg_ca_score       IS NULL THEN 1 ELSE 0 END) AS null_ca,
    SUM(CASE WHEN avg_exam_score      IS NULL THEN 1 ELSE 0 END) AS null_exam,
    SUM(CASE WHEN avg_attendance_pct  IS NULL THEN 1 ELSE 0 END) AS null_att,
    SUM(CASE WHEN risk_score          IS NULL THEN 1 ELSE 0 END) AS null_risk
FROM vw_risk_scores WHERE academic_year='2024/2025' AND semester='First';

-- 4. College-level summary
SELECT * FROM vw_college_summary ORDER BY college_avg_score DESC;

-- 5. Department summary (shows college alongside each dept)
SELECT * FROM vw_department_summary ORDER BY college, dept_avg_score DESC;

-- 6. Populate predictions table
CALL sp_populate_risk_predictions('2024/2025','First');

-- 7. Top 10 most at-risk students
SELECT student_id, full_name, department, college, level,
       risk_score, avg_total_score, avg_attendance_pct, risk_category
FROM vw_at_risk_students
WHERE academic_year='2024/2025' AND semester='First'
LIMIT 10;
